    .cancellation-reason {
        margin-top: 20px;
        padding: 20px;
        background: #f8f9fa;
        border-radius: 12px;
        border: 1px solid #e9ecef;
    }

    .cancellation-reason label {
        color: #495057;
        font-weight: 600;
        margin-bottom: 8px;
        display: block;
    }

    .cancellation-reason textarea {
        width: 100%;
        padding: 12px;
        border: 2px solid #e9ecef;
        border-radius: 8px;
        font-family: inherit;
        font-size: 0.9em;
        resize: vertical;
        transition: border-color 0.3s ease;
        margin-top: 8px;
    }

    .cancellation-reason textarea:focus {
        outline: none;
        border-color: #667eea;
        box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.1);
    }

    .cancellation-requested-message {
        margin-top: 20px;
        padding: 15px;
        background: #fff3cd;
        border: 1px solid #ffeaa7;
        border-radius: 8px;
        border-left: 4px solid #f39c12;
    }

    .cancellation-requested-message p {
        margin: 0;
        color: #856404;
        font-weight: 500;
        font-size: 0.9em;
    }

    td.booking_status span,
    .booking_status span {
        margin: 0;
        padding: 8px 16px;
        font-weight: 600;
        color: #ffffff;
        background: linear-gradient(135deg, #ff6b6b 0%, #ee5a52 100%);
        display: inline-block;
        border-radius: 20px;
        font-size: 0.85em;
        text-transform: uppercase;
        letter-spacing: 0.5px;
        box-shadow: 0 2px 8px rgba(255, 107, 107, 0.3);
    }

    .booking_status {
        padding: 15px 0;
        margin-bottom: 15px;
    }

    a.disabled {
        color: #adb5bd;
        cursor: not-allowed;
        text-decoration: none;
    }

    @media (max-width: 768px) {
        .trip-status-board {
            margin: 15px;
            padding: 20px;
            max-width: none;
        }
        
        .trip-status-board h3 {
            font-size: 1.2em;
        }
        
        .trip-status-board button {
            width: 100%;
            margin: 10px 0;
        }
    }
